#include<bits/stdc++.h>
using namespace std;

vector<int> adj[101];  // 邻接表表示图
int dist[101];         // 存储到服务中心的最短距离
int n, m;

// 从服务中心n开始进行BFS，计算所有节点到n的最短距离
void bfs() {
    // 初始化距离数组为-1（表示不可达）
    memset(dist, -1, sizeof(dist));

    queue<int> q;
    // 服务中心到自己的距离为0
    dist[n] = 0;
    q.push(n);

    while (!q.empty()) {
        int curr = q.front();
        q.pop();

        // 遍历当前节点的所有邻居
        for (int neighbor : adj[curr]) {
            // 如果邻居未被访问过
            if (dist[neighbor] == -1) {
                // 距离为当前节点距离+1
                dist[neighbor] = dist[curr] + 1;
                q.push(neighbor);
            }
        }
    }
}

int main() {
    cin >> n >> m;

    // 读取路线信息，构建无向图
    for (int i = 1; i <= m; i++) {
        int x, y;
        cin >> x >> y;
        adj[x].push_back(y);
        adj[y].push_back(x);
    }

    // 从服务中心开始BFS
    bfs();

    // 输出1到n-1每个景点到服务中心的最短距离
    for (int i = 1; i < n; i++) {
        cout << dist[i] << " ";
    }

    return 0;
}
